#include <stdio.h>
#include <stdlib.h>

/* == EXEMPLE ================================================
 * Pile (stack) avec push et print via liste chainee
 * Chaque noeud pointe vers le suivant; push ajoute en tete.
 * =========================================================== */
typedef struct SNode { int val; struct SNode *next; } SNode;

SNode *example_push(SNode *top, int val) {
    SNode *n = malloc(sizeof(SNode));
    if (!n) return top;
    n->val = val;
    n->next = top;
    return n;
}
void example_print_stack(SNode *top) {
    for (SNode *cur = top; cur; cur = cur->next)
        printf("%d ", cur->val);
    printf("\n");
}
void example_free_stack(SNode *top) {
    while (top) { SNode *tmp = top->next; free(top); top = tmp; }
}
void example_demo(void) {
    SNode *stack = NULL;
    stack = example_push(stack, 10);
    stack = example_push(stack, 20);
    stack = example_push(stack, 30);
    example_print_stack(stack);
    example_free_stack(stack);
}
